const crypto = require('crypto');
const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) throw new Error('Missing x-profunda-signature header');
if (!webhookBody || typeof webhookBody !== 'object') throw new Error('Missing or invalid webhook body');
if (webhookBody.workflow_key !== 'partner_enrich') throw new Error('workflow_key must be partner_enrich, got: ' + webhookBody.workflow_key);
if (!webhookBody.run_id || typeof webhookBody.run_id !== 'string') throw new Error('Missing run_id');

const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
if (hmac !== signature) throw new Error('Invalid HMAC signature');

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;

if (!input.org_name || typeof input.org_name !== 'string') {
  throw new Error('org_name is required for partner_enrich');
}

let website_url = input.website_url || null;
if (website_url && typeof website_url === 'string') {
  website_url = website_url.trim();
  if (!/^https?:\/\//i.test(website_url)) website_url = 'https://' + website_url;
}

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'partner_enrich',
    org_id: input.org_id || null,
    org_name: input.org_name,
    website_url: website_url,
    triggered_by: input.triggered_by || null
  }
}];

const validated = $('Validate Input').first().json;
const websiteUrl = validated.website_url;

if (!websiteUrl) {
  return [{
    json: {
      run_id: validated.run_id,
      org_id: validated.org_id,
      org_name: validated.org_name,
      website_url: null,
      crawl_skipped: true,
      skip_reason: 'No website URL provided for org'
    }
  }];
}

return [{
  json: {
    run_id: validated.run_id,
    org_id: validated.org_id,
    org_name: validated.org_name,
    website_url: websiteUrl,
    crawl_skipped: false
  }
}];

const resolveData = $('Resolve URL').first().json;
const run_id = resolveData.run_id;
const org_id = resolveData.org_id;
const org_name = resolveData.org_name;

if (resolveData.crawl_skipped) {
  return [{ json: { run_id, org_id, org_name, enrichment: {}, signals: [], crawl_skipped: true, skip_reason: resolveData.skip_reason } }];
}

let scrapeData;
try { scrapeData = $('Firecrawl Scrape').first().json; } catch (e) {
  return [{ json: { run_id, org_id, org_name, enrichment: {}, signals: [], crawl_error: 'Firecrawl did not produce output: ' + String(e.message).slice(0, 200) } }];
}

if (scrapeData.error || !scrapeData.success) {
  return [{ json: { run_id, org_id, org_name, enrichment: {}, signals: [], crawl_error: scrapeData.error || 'Firecrawl returned unsuccessful response' } }];
}

const markdown = scrapeData.data?.markdown || scrapeData.markdown || '';
const links = scrapeData.data?.links || scrapeData.links || [];
const metadata = scrapeData.data?.metadata || scrapeData.metadata || {};
const contentLower = markdown.toLowerCase();

// Build enrichment object
const enrichment = {
  title: (metadata.title || '').slice(0, 200),
  description: (metadata.description || '').slice(0, 500),
  source_url: metadata.sourceURL || resolveData.website_url,
  content_length: markdown.length,
  links_found: links.length
};

// Deterministic signal extraction
const signals = [];
const hiringKw = ['hiring', 'careers', 'job openings', 'join our team', 'open positions'];
const hiringMatches = hiringKw.filter(kw => contentLower.includes(kw));
if (hiringMatches.length > 0) signals.push({ signal_type: 'hiring_activity', summary: 'Hiring signals: ' + hiringMatches.join(', '), confidence: 0.8 });

const expansionKw = ['new location', 'expanding', 'partnership', 'launched', 'announcement'];
const expansionMatches = expansionKw.filter(kw => contentLower.includes(kw));
if (expansionMatches.length > 0) signals.push({ signal_type: 'expansion_activity', summary: 'Expansion signals: ' + expansionMatches.join(', '), confidence: 0.7 });

const techKw = ['digital equity', 'broadband', 'computer', 'device', 'technology access', 'digital inclusion'];
const techMatches = techKw.filter(kw => contentLower.includes(kw));
if (techMatches.length > 0) signals.push({ signal_type: 'tech_relevance', summary: 'Digital equity relevance: ' + techMatches.join(', '), confidence: 0.85 });

const fundingKw = ['funding', 'grant', 'awarded', 'million', 'investment'];
const fundingMatches = fundingKw.filter(kw => contentLower.includes(kw));
if (fundingMatches.length > 0) signals.push({ signal_type: 'funding_activity', summary: 'Funding signals: ' + fundingMatches.join(', '), confidence: 0.75 });

return [{ json: { run_id, org_id, org_name, enrichment, signals, signal_count: signals.length, source_url: resolveData.website_url, crawl_error: null } }];

const validated = $('Validate Input').first().json;
let data = null;
let error = null;
let failed_node = null;

try { data = $('Extract Enrichment').first().json; } catch (e1) {
  try { data = $('Skip Crawl').first().json; } catch (e2) {
    error = 'Neither Extract Enrichment nor Skip Crawl produced output';
    failed_node = 'Extract Enrichment';
  }
}

if (data && data.crawl_error) { error = data.crawl_error; failed_node = 'Firecrawl Scrape'; }

let result = null;
if (!error && data) {
  result = { enrichment: data.enrichment || {}, signals: data.signals || [], signal_count: data.signal_count || 0, org_id: data.org_id, org_name: data.org_name, source_url: data.source_url || null, crawl_skipped: data.crawl_skipped || false };
}

return [{ json: { run_id: validated.run_id, workflow_key: 'partner_enrich', payload: { result, error, failed_node } } }];
